// RerankerModelTypePlugin in-process reranker registered via the plugin system.
//
// The caller registers a `RerankerBackend` once (e.g. a
// wrapper around a `sentence-transformers` cross-encoder or a provider client),
// then references it by name in config. Kreuzberg calls back into the registered
// backend — no HuggingFace download, no ONNX Runtime requirement.
//
// When this variant is selected, only `max_rerank_duration_secs` applies.
// Model-loading fields (`batch_size`, `cache_dir`, `show_download_progress`,
// `acceleration`) are ignored — the host owns the model lifecycle.
//
// See `register_reranker_backend`.
type RerankerModelTypePlugin struct {
	// Name the backend was registered under via `register_reranker_backend`.
	Name string `json:"name"`
}

func (RerankerModelTypePlugin) isRerankerModelType() {}
func (RerankerModelTypePlugin) Type() string         { return "plugin" }
func (v RerankerModelTypePlugin) MarshalJSON() ([]byte, error) {
	type aux struct {
		Type string `json:"type"`
		Name string `json:"name"`
	}
	return json.Marshal(aux{
		Type: v.Type(),
		Name: v.Name,
	})
}

// UnmarshalRerankerModelType decodes JSON data into the appropriate concrete RerankerModelType variant.
func UnmarshalRerankerModelType(data []byte) (RerankerModelType, error) {
	var wire struct {
		Type string `json:"type"`
	}
	if err := json.Unmarshal(data, &wire); err != nil {
		return nil, err
	}

	switch wire.Type {
	case "preset":
		var v RerankerModelTypePreset
		if err := json.Unmarshal(data, &v); err != nil {
			return nil, err
		}
		return v, nil
	case "custom":
		var v RerankerModelTypeCustom
		if err := json.Unmarshal(data, &v); err != nil {
			return nil, err
		}
		return v, nil
	case "llm":
		var v RerankerModelTypeLlm
		if err := json.Unmarshal(data, &v); err != nil {
			return nil, err
		}
		return v, nil
	case "plugin":
		var v RerankerModelTypePlugin
		if err := json.Unmarshal(data, &v); err != nil {
			return nil, err
		}
		return v, nil
	}
	return nil, fmt.Errorf("unknown RerankerModelType type: %q", wire.Type)
}

