// DetectQrCodes detect QR codes in the bytes of an `ExtractedImage`.
//
// `format_hint` is currently unused — the `image` crate auto-detects the
// container format from magic bytes — but the parameter is retained so future
// backends (e.g. a WebP-via-`webp-decoder` variant) can use it without an API
// break.
//
// Returns an empty vector on any of:
//
// - Empty input.
// - Image-decode failure.
// - No QR grids detected.
// - All detected grids fail to decode.
//
// Successfully decoded QR codes carry their payload, a confidence of `1.0`
// (rqrr does not expose per-grid confidence; a successful decode is treated
// as high-confidence by convention), and the pixel-space bounding box derived
// from the four corner points of the grid.
func DetectQrCodes(imageBytes []byte, formatHint *string) []QrCode {
	var cImageBytes *C.uint8_t
	if len(imageBytes) > 0 {
		var cImageBytesPinner runtime.Pinner
		cImageBytesPinner.Pin(&imageBytes[0])
		defer cImageBytesPinner.Unpin()
		cImageBytes = (*C.uint8_t)(unsafe.Pointer(&imageBytes[0]))
	}
	cImageBytesLen := C.uintptr_t(len(imageBytes))

	var cFormatHint *C.char
	if formatHint != nil {
		cFormatHint = C.CString(*formatHint)
		defer C.free(unsafe.Pointer(cFormatHint))
	}

	ptr := C.kreuzberg_detect_qr_codes(cImageBytes, cImageBytesLen, cFormatHint)
	return func() []QrCode {
		if ptr == nil {
			return nil
		}
		defer C.kreuzberg_free_string(ptr)
		var result []QrCode
		if err := json.Unmarshal([]byte(C.GoString(ptr)), &result); err != nil {
			return nil
		}
		return result
	}()
}

