// ClassifyPages run page classification against an extraction result.
//
// Mutates `result.page_classifications` with one entry per non-empty page and
// appends every LLM call's usage to `result.llm_usage`.
//
// Errors are returned when returns the first error encountered when rendering the prompt or calling the
// LLM. Partially produced classifications are discarded so callers do not see
// a half-populated vector.
func ClassifyPages(result ExtractionResult, config PageClassificationConfig) error {
	jsonBytescResult, err := json.Marshal(result)
	if err != nil {
		return fmt.Errorf("failed to marshal: %w", err)
	}
	// When the parameter is a nil pointer (Option<&T> on the Rust side), json.Marshal
	// emits "null" which the FFI's _from_json rejects. Substitute "{}" so a default
	// instance is constructed instead — semantically equivalent to None for query types
	// whose fields are all optional with serde(default).
	if string(jsonBytescResult) == "null" {
		jsonBytescResult = []byte("{}")
	}
	tmpStrcResult := C.CString(string(jsonBytescResult))
	cResult := C.kreuzberg_extraction_result_from_json(tmpStrcResult)
	C.free(unsafe.Pointer(tmpStrcResult))
	if cResult == nil {
		return fmt.Errorf("failed to create extraction_result: %s", C.GoString(C.kreuzberg_last_error_context()))
	}
	defer C.kreuzberg_extraction_result_free(cResult)

	jsonBytescConfig, err := json.Marshal(config)
	if err != nil {
		return fmt.Errorf("failed to marshal: %w", err)
	}
	// When the parameter is a nil pointer (Option<&T> on the Rust side), json.Marshal
	// emits "null" which the FFI's _from_json rejects. Substitute "{}" so a default
	// instance is constructed instead — semantically equivalent to None for query types
	// whose fields are all optional with serde(default).
	if string(jsonBytescConfig) == "null" {
		jsonBytescConfig = []byte("{}")
	}
	tmpStrcConfig := C.CString(string(jsonBytescConfig))
	cConfig := C.kreuzberg_page_classification_config_from_json(tmpStrcConfig)
	C.free(unsafe.Pointer(tmpStrcConfig))
	if cConfig == nil {
		return fmt.Errorf("failed to create page_classification_config: %s", C.GoString(C.kreuzberg_last_error_context()))
	}
	defer C.kreuzberg_page_classification_config_free(cConfig)

	C.kreuzberg_classify_pages(cResult, cConfig)
	return lastError()
}

