// Compare two extraction results and return a structured diff.
//
// The comparison is purely structural — no I/O, no side effects. All fields
// of [`ExtractionDiff`] are populated according to the provided [`DiffOptions`].
//
// Arguments:
//   - a: — the "before" extraction result
//   - b: — the "after" extraction result
//   - opts: — controls which sections are compared and optional truncation
//
// Example:
//
//	let mut a = ExtractionResult::default();
//	let mut b = ExtractionResult::default();
//	a.content = "Hello world".to_string();
//	b.content = "Hello Rust".to_string();
//
//	let diff = compare(&a, &b, &DiffOptions::default());
//	assert_eq!(diff.content_diff.len(), 1);
func Compare(a ExtractionResult, b ExtractionResult, opts DiffOptions) (*ExtractionDiff, error) {
	jsonBytesca, err := json.Marshal(a)
	if err != nil {
		return nil, fmt.Errorf("failed to marshal: %w", err)
	}
	// When the parameter is a nil pointer (Option<&T> on the Rust side), json.Marshal
	// emits "null" which the FFI's _from_json rejects. Substitute "{}" so a default
	// instance is constructed instead — semantically equivalent to None for query types
	// whose fields are all optional with serde(default).
	if string(jsonBytesca) == "null" {
		jsonBytesca = []byte("{}")
	}
	tmpStrca := C.CString(string(jsonBytesca))
	ca := C.kreuzberg_extraction_result_from_json(tmpStrca)
	C.free(unsafe.Pointer(tmpStrca))
	if ca == nil {
		return nil, fmt.Errorf("failed to create extraction_result: %s", C.GoString(C.kreuzberg_last_error_context()))
	}
	defer C.kreuzberg_extraction_result_free(ca)

	jsonBytescb, err := json.Marshal(b)
	if err != nil {
		return nil, fmt.Errorf("failed to marshal: %w", err)
	}
	// When the parameter is a nil pointer (Option<&T> on the Rust side), json.Marshal
	// emits "null" which the FFI's _from_json rejects. Substitute "{}" so a default
	// instance is constructed instead — semantically equivalent to None for query types
	// whose fields are all optional with serde(default).
	if string(jsonBytescb) == "null" {
		jsonBytescb = []byte("{}")
	}
	tmpStrcb := C.CString(string(jsonBytescb))
	cb := C.kreuzberg_extraction_result_from_json(tmpStrcb)
	C.free(unsafe.Pointer(tmpStrcb))
	if cb == nil {
		return nil, fmt.Errorf("failed to create extraction_result: %s", C.GoString(C.kreuzberg_last_error_context()))
	}
	defer C.kreuzberg_extraction_result_free(cb)

	jsonBytescOpts, err := json.Marshal(opts)
	if err != nil {
		return nil, fmt.Errorf("failed to marshal: %w", err)
	}
	// When the parameter is a nil pointer (Option<&T> on the Rust side), json.Marshal
	// emits "null" which the FFI's _from_json rejects. Substitute "{}" so a default
	// instance is constructed instead — semantically equivalent to None for query types
	// whose fields are all optional with serde(default).
	if string(jsonBytescOpts) == "null" {
		jsonBytescOpts = []byte("{}")
	}
	tmpStrcOpts := C.CString(string(jsonBytescOpts))
	cOpts := C.kreuzberg_diff_options_from_json(tmpStrcOpts)
	C.free(unsafe.Pointer(tmpStrcOpts))
	if cOpts == nil {
		return nil, fmt.Errorf("failed to create diff_options: %s", C.GoString(C.kreuzberg_last_error_context()))
	}
	defer C.kreuzberg_diff_options_free(cOpts)

	ptr := C.kreuzberg_compare(ca, cb, cOpts)
	defer C.kreuzberg_extraction_diff_free(ptr)
	jsonPtr := C.kreuzberg_extraction_diff_to_json(ptr)
	if jsonPtr == nil {
		return nil, fmt.Errorf("failed to convert to JSON")
	}
	defer C.kreuzberg_free_string(jsonPtr)
	var result ExtractionDiff
	if err := json.Unmarshal([]byte(C.GoString(jsonPtr)), &result); err != nil {
		return nil, fmt.Errorf("failed to unmarshal: %w", err)
	}
	return &result, nil
}

// ExtractRegionWithVlm extract content from a pre-cropped image region using a VLM.
//
// The caller is responsible for cropping the page image to the region's bounding
// box before calling this function. The `image_bytes` parameter must contain the
// raw bytes of the **cropped** region image (JPEG, PNG, WebP, etc.).
//
// Arguments:
//   - image_bytes: — Raw bytes of the **pre-cropped** region image.
//   - image_mime: — MIME type of the image (`"image/png"`, `"image/jpeg"`, etc.).
//   - region_kind: — Content type of the region, used to select the default prompt.
//   - llm_config: — LLM provider and model configuration.
//   - custom_prompt: — Optional override for the default per-region prompt template.
//
// Returns extracted Markdown text from the VLM, or an error if the VLM call fails.
//
// Errors are returned when - `Ocr` if the VLM call fails or returns no content.
// - `MissingDependency` if the liter-llm client cannot
// be initialised.
//
// Example:
//
//	let image_bytes: Vec<u8> = std::fs::read("cropped_figure.png")?;
//	let config = LlmConfig {
//	    model: "openai/gpt-4o-mini".to_string(),
//	    base_url: Some("http://localhost:9999".to_string()),
//	    ..Default::default()
//	};
//	let markdown = extract_region_with_vlm(
//	    &image_bytes,
//	    "image/png",
//	    RegionKind::Figure,
//	    &config,
//	    None,
//	)
//	.await?;
//	println!("Extracted: {markdown}");
func ExtractRegionWithVlm(imageBytes []byte, imageMime string, regionKind RegionKind, llmConfig LlmConfig, customPrompt *string) (string, error) {
	var cImageBytes *C.uint8_t
	if len(imageBytes) > 0 {
		var cImageBytesPinner runtime.Pinner
		cImageBytesPinner.Pin(&imageBytes[0])
		defer cImageBytesPinner.Unpin()
		cImageBytes = (*C.uint8_t)(unsafe.Pointer(&imageBytes[0]))
	}
	cImageBytesLen := C.uintptr_t(len(imageBytes))

	cImageMime := C.CString(imageMime)
	defer C.free(unsafe.Pointer(cImageMime))

	cRegionKindStr := C.CString(string(regionKind))
	defer C.free(unsafe.Pointer(cRegionKindStr))
	cRegionKind := C.kreuzberg_region_kind_from_str(cRegionKindStr)

	jsonBytescLlmConfig, err := json.Marshal(llmConfig)
	if err != nil {
		return "", fmt.Errorf("failed to marshal: %w", err)
	}
	// When the parameter is a nil pointer (Option<&T> on the Rust side), json.Marshal
	// emits "null" which the FFI's _from_json rejects. Substitute "{}" so a default
	// instance is constructed instead — semantically equivalent to None for query types
	// whose fields are all optional with serde(default).
	if string(jsonBytescLlmConfig) == "null" {
		jsonBytescLlmConfig = []byte("{}")
	}
	tmpStrcLlmConfig := C.CString(string(jsonBytescLlmConfig))
	cLlmConfig := C.kreuzberg_llm_config_from_json(tmpStrcLlmConfig)
	C.free(unsafe.Pointer(tmpStrcLlmConfig))
	if cLlmConfig == nil {
		return "", fmt.Errorf("failed to create llm_config: %s", C.GoString(C.kreuzberg_last_error_context()))
	}
	defer C.kreuzberg_llm_config_free(cLlmConfig)

	var cCustomPrompt *C.char
	if customPrompt != nil {
		cCustomPrompt = C.CString(*customPrompt)
		defer C.free(unsafe.Pointer(cCustomPrompt))
	}

	ptr := C.kreuzberg_extract_region_with_vlm(cImageBytes, cImageBytesLen, cImageMime, cRegionKind, cLlmConfig, cCustomPrompt)
	if err := lastError(); err != nil {
		if ptr != nil {
			C.kreuzberg_free_string(ptr)
		}
		return "", err
	}
	defer C.kreuzberg_free_string(ptr)
	return C.GoString(ptr), nil
}

// ExtractKeywords extract keywords from text using the specified algorithm.
//
// This is the unified entry point for keyword extraction. The algorithm
// used is determined by `config.algorithm`.
//
// Arguments:
//   - text: The text to extract keywords from
//   - config: Keyword extraction configuration
//
// Returns a vector of keywords sorted by relevance (highest score first).
//
// Errors are returned when returns an error if:
// - The specified algorithm feature is not enabled
// - Keyword extraction fails
//
// Example:
//
//	let text = "Document intelligence with Rust provides memory safety.";
//	let config = KeywordConfig::default()
//	    .with_max_keywords(10)
//	    .with_language("en");
//
//	let keywords = extract_keywords(text, &config)?;
//
//	for keyword in keywords {
//	    println!("{}: {:.3}", keyword.text, keyword.score);
//	}
func ExtractKeywords(text string, config KeywordConfig) ([]Keyword, error) {
	cText := C.CString(text)
	defer C.free(unsafe.Pointer(cText))

	jsonBytescConfig, err := json.Marshal(config)
	if err != nil {
		return nil, fmt.Errorf("failed to marshal: %w", err)
	}
	// When the parameter is a nil pointer (Option<&T> on the Rust side), json.Marshal
	// emits "null" which the FFI's _from_json rejects. Substitute "{}" so a default
	// instance is constructed instead — semantically equivalent to None for query types
	// whose fields are all optional with serde(default).
	if string(jsonBytescConfig) == "null" {
		jsonBytescConfig = []byte("{}")
	}
	tmpStrcConfig := C.CString(string(jsonBytescConfig))
	cConfig := C.kreuzberg_keyword_config_from_json(tmpStrcConfig)
	C.free(unsafe.Pointer(tmpStrcConfig))
	if cConfig == nil {
		return nil, fmt.Errorf("failed to create keyword_config: %s", C.GoString(C.kreuzberg_last_error_context()))
	}
	defer C.kreuzberg_keyword_config_free(cConfig)

	ptr := C.kreuzberg_extract_keywords(cText, cConfig)
	if err := lastError(); err != nil {
		return nil, err
	}
	if ptr == nil {
		return nil, fmt.Errorf("failed to get result")
	}
	defer C.kreuzberg_free_string(ptr)
	var result []Keyword
	if err := json.Unmarshal([]byte(C.GoString(ptr)), &result); err != nil {
		return nil, fmt.Errorf("failed to unmarshal: %w", err)
	}
	return result, nil
}

// RenderPdfPageToPng render a single PDF page to PNG bytes.
//
// Returns raw PNG-encoded bytes for the specified page at the given DPI.
// Uses pdf_oxide with tiny-skia for pure-Rust rendering.
//
// For pages with extreme dimensions (very wide vector diagrams, etc.) the
// effective DPI may be automatically reduced to avoid rasterizer failure.
// A warning is logged when this happens.
//
// Arguments:
//   - pdf_bytes: Raw PDF file bytes
//   - page_index: Zero-based page index
//   - dpi: Resolution in dots per inch (default: 150)
//   - password: Optional password for encrypted PDFs
//
// Errors are returned when returns `KreuzbergError::Parsing` if the PDF cannot be opened, authenticated,
// or rendered, or if `page_index` is out of range.
func RenderPdfPageToPng(pdfBytes []byte, pageIndex uint, dpi *int32, password *string) ([]byte, error) {
	var cPdfBytes *C.uint8_t
	if len(pdfBytes) > 0 {
		var cPdfBytesPinner runtime.Pinner
		cPdfBytesPinner.Pin(&pdfBytes[0])
		defer cPdfBytesPinner.Unpin()
		cPdfBytes = (*C.uint8_t)(unsafe.Pointer(&pdfBytes[0]))
	}
	cPdfBytesLen := C.uintptr_t(len(pdfBytes))

	cPageIndex := C.size_t(uint(pageIndex))

	var cDpi C.int32_t = C.int32_t(int32(2147483647))
	if dpi != nil {
		cDpi = C.int32_t(int32(*dpi))
	}

	var cPassword *C.char
	if password != nil {
		cPassword = C.CString(*password)
		defer C.free(unsafe.Pointer(cPassword))
	}

	var outPtr *C.uint8_t
	var outLen, outCap C.uintptr_t
	rc := C.kreuzberg_render_pdf_page_to_png(cPdfBytes, cPdfBytesLen, cPageIndex, cDpi, cPassword, &outPtr, &outLen, &outCap)
	if rc != 0 {
		return nil, lastError()
	}
	if outPtr == nil {
		return nil, lastError()
	}
	result := C.GoBytes(unsafe.Pointer(outPtr), C.int(outLen))
	C.kreuzberg_free_bytes(outPtr, outLen, outCap)
	return result, nil
}

// DetectMimeType detect the MIME type of a file at the given path.
//
// Uses the file extension and optionally the file content to determine the MIME type.
// Set `check_exists` to `true` to verify the file exists before detection.
func DetectMimeType(path string, checkExists bool) (string, error) {
	cPath := C.CString(path)
	defer C.free(unsafe.Pointer(cPath))

	var cCheckExists C.int32_t
	if checkExists {
		cCheckExists = 1
	} else {
		cCheckExists = 0
	}

	ptr := C.kreuzberg_detect_mime_type(cPath, cCheckExists)
	if err := lastError(); err != nil {
		if ptr != nil {
			C.kreuzberg_free_string(ptr)
		}
		return "", err
	}
	defer C.kreuzberg_free_string(ptr)
	return C.GoString(ptr), nil
}

